#' Compare results
#'
#' Given results table, prepares a "heatmap"
#' summarising main results of each step of
#' the regression robustness analyses.
#'
#' @param res List. Tables generated by
#'   \code{stat_test}.
#'
#' @returns {ggplot2} figure.
#'
#' @export
plot_compare_results <- function(res) {
  tab <- purrr::map_dfr(names(res), function(i) {
    res[[i]]$mPA |>
      dplyr::filter(Effect == "total" & Analysis != "0") |>
      dplyr::select(
        Outcome, tidyselect::starts_with("mPA"), s.value, sig_FDR, Analysis
      ) |>
      dplyr::mutate(
        Analysis = factor(
          dplyr::case_when(
            Analysis == 1 ~ "SuperAging Correlates",
            Analysis == 2 ~ "SuperAging Components"
          ),
          levels = paste("SuperAging", c("Correlates", "Components"), sep = " "),
          ordered = TRUE
        ),
        Step = factor(
          dplyr::case_when(
            i == "unadjusted" ~ "0",
            i == "adjusted" ~ "(i)",
            i == "transformed" ~ "(ii)",
            i == "g-computation" ~ "(iii)",
            i == "g-computation_plus" ~ "(iv)"
          ),
          levels = c("0", "(i)", "(ii)", "(iii)", "(iv)"),
          ordered = TRUE
        ),
        Outcome = factor(
          dplyr::recode(
            Outcome,
            GAI = "GAI",
            GDS15 = "GDS-15",
            FAQ = "FAQ",
            Z_SA = "Cognition CS",
            Anx = "Anxiety risk",
            Depr = "Depression risk",
            cPA = "cPA",
            SA = "SA",
            Delayed_recall_z = "Memory (delayed recall)",
            TMT_B_z = "TMT-B",
            BNT_30_z = "BNT-30",
            VF_Animals_z = "Verbal Fluency (animals)"
          ),
          levels = rev(c(
            "GAI",
            "GDS-15",
            "FAQ",
            "Cognition CS",
            "Anxiety risk",
            "Depression risk",
            "cPA",
            "SA",
            "Memory (delayed recall)",
            "TMT-B",
            "BNT-30",
            "Verbal Fluency (animals)"
          )),
          ordered = TRUE
        )
      ) |>
      dplyr::arrange(Outcome)
  })
  # Plot it:
  tab |>
    ggplot2::ggplot() +
    ggplot2::aes(x = Step, y = Outcome, fill = s.value) +
    ggplot2::geom_tile() +
    ggplot2::labs(x = "Analysis", y = NULL, fill = "s value") +
    ggplot2::geom_point(
      data = subset(tab, sig_FDR == "*"),
      ggplot2::aes(x = Step, y = Outcome),
      shape = 8,
      colour = "#08306b",
      size = 2
    ) +
    ggplot2::scale_fill_gradient(low = "grey96", high = "#e34a33") +
    ggh4x::facet_grid2(ggplot2::vars(Analysis), scales = "free_y", axes = "all", space = "free") +
    ggplot2::theme_bw() +
    ggplot2::theme()
}
